var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"어……? 아빠다!","JPN":"あれ……？　パパだ！","ENG":"Huh...? It's Daddy!","TWN":"嗯……？是爸爸！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"드디어 돌아왔구나! 기다리고 있었어!","JPN":"やっと帰って来たんだね！　待ってたんだよ！","ENG":"You're finally back! I've been waiting for you!","TWN":"你終於回來了！我等你等好久喔！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L7_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"회사 사람들도 아빠를 엄청 기다리고 있었다구! 부사장 아줌마는 마구 펄펄 뛰더라니까?","JPN":"社員の人もパパをすっごく待ってたよ！　副社長なんてぴょんぴょん跳ねてたんだから！","ENG":"The people at the company have also been waiting for you! The Vice President Lady was sooo angry!","TWN":"公司的人也都在等爸爸回來呢！副總大嬸開心到都跳起來咧！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그래서 아빠를 대신해서 시그마가 회사를 열심히 지켰다? 에헤헤. 나 잘했지?","JPN":"だから、シグマがパパの代わりに会社を一生懸命守ったんだよ？　えらいでしょ？","ENG":"So Sigma protected the company while you were away, heh heh heh. Are you proud of me?","TWN":"爸爸你看，西格瑪有幫你把公司顧好吧？嘿嘿嘿，我很棒吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠가 사라져 버려서 많이 걱정했지만, 시그마는 반드시 돌아올 거라고 믿고 있었어.","JPN":"いなくなってすごく心配したけど、シグマはパパが絶対帰ってくるって信じてたよ。","ENG":"Sigma was worried because Daddy disappeared, but Sigma knew you'd come back.","TWN":"爸爸消失後西格瑪一直很擔心，但我相信爸爸一定會回來的。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"왜냐하면 아빠는 절대로 시그마를 두고 떠나지 않을테니까!","JPN":"だって、パパは絶対シグマを置いて行ったりしないから！","ENG":"Because Daddy would never leave without Sigma!","TWN":"因為爸爸是絕對不可能扔下西格瑪不管的！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"히힛, 지금까지 뭘 하고 있었냐고? 아빠가 없는 동안 회사 일을 착실히 맡고 있었지.","JPN":"へへっ、今日まで何していたのかって？　パパがいない間は会社の仕事をしっかりやってたよ。","ENG":"Teehee, you're curious about what I was doing? I was responsibly handling company work while Daddy was away.","TWN":"嘻嘻，我這段時間都做了什麼嗎？當然是認真上班囉！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"엣헴! 시그마는 그동안 미래전략실 실장으로서의 책임을 다 하고 있었단 말씀!","JPN":"えっへん！　シグマは未来戦略室の室長として責任を果たしたってこと！","ENG":"Ahem! Sigma was doing her part as the head of the Future Strategy Department!","TWN":"咳咳！西格瑪是一個盡責的未來戰略室室長喔！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오늘 해야 할 일은 사내 복도 청소, 탕비실 물품 채우기, 회사 주변 치안 관리!","JPN":"今日やることはね、会社の廊下掃除でしょ、給湯室の品物の補充に、会社の周りの治安管理！","ENG":"Today, I was supposed to clean the company hallway, restock the break room, and make sure the company premises are safe!","TWN":"我今天的工作是打掃走廊，補充茶水間物品，跟公司周圍的治安管理！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"이것 봐라~ 바닥에 반짝반짝 윤기가 나지? 탕비실 과자 음료도 가득! 거리 주변 치안도 이상 무!","JPN":"みてみて～、床がピカピカでしょ？　給湯室のお菓子と飲み物もどっさり！　会社の周りの治安も異常なし！","ENG":"Look, look! The floor is shiny! And the break room is full of snacks! And the streets are safer than ever!","TWN":"爸爸你看～地板是不是亮晶晶的？茶水間裡的餅乾和飲料也都補滿了！周圍也沒有任何異狀！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"에헤헤… 아빠가 칭찬해 주니까 엄청 기쁘다.","JPN":"えへへ……パパが褒めてくれてすごく嬉しいな。","ENG":"Heh heh heh... I love when Daddy compliments me.","TWN":"嘿嘿嘿…謝謝爸爸的誇獎，好開心～"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"기다리는 사람에게는 복이 온다던데 책에서 본 내용이 정말이었어!","JPN":"待っている人には福が来るって本に書いてあったけど、本当だった！","ENG":"I read that good things come to those who wait. The book was true!","TWN":"我看書上說，等待的人是有福的，這話是真的欸！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"있지 있지 아빠! 그럼 오늘은 뭐 할 꺼야? 오랜만에 시그마랑 같이 신나게 놀자!","JPN":"ねーねーパパ！　じゃあ、今日は何しようか？　久しぶりにシグマと思いっきり遊ぼう！","ENG":"Oh, Daddy! What are you going to do today? Play with Sigma! It's been too long!","TWN":"爸爸，爸爸！那你今天要做什麼？久違地和西格瑪一起玩嘛！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"뭘 하면 좋을까?","JPN":"何がいいかなあ？","ENG":"What should we do?","TWN":"要玩什麼呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"시그마는 아빠랑 둘이 놀이동산 가고 싶어! 키즈카페라는 곳도 재밌을 것 같아! 아니면 책 읽어주는 것도 너무 좋아!","JPN":"シグマはパパと二人で遊園地に行きたい！　キッズカフェっていう所も面白そうだなあ！　本を読んでくれるのでもいいよ！","ENG":"Sigma wants to go to an amusement park with Daddy! And the place called kids cafe sounds fun, too! Or Daddy can read a book for me!","TWN":"西格瑪想和爸爸一起去遊樂園玩！親子樂園好像也很好玩！還是你讀故事書給我聽！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아참, 아빠는 열심히 일해야 하니까 많이 바쁜거였지……?","JPN":"あ、そうだ。パパはお仕事をしなきゃいけないから、すごく忙しいんだったよね……？","ENG":"Oh, Daddy's busy because of work, right...?","TWN":"不過，爸爸那麼認真工作，應該很忙吧……？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"괜찮아. 아빠는 돌아와 줬는걸? 시그마는 착한 아이니까 꾹 참고 기다려 줄 수 있어!","JPN":"大丈夫。パパが帰ってきてくれたんだもん。シグマはいい子だから我慢して待てるよ！","ENG":"It's okay. Daddy came back. Sigma can be a good girl and wait more!","TWN":"沒關係，爸爸會回來的吧？西格瑪是好孩子，會乖乖等爸爸回來！"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 시그마는 여기서 기다리고 있을 테니까 시간 나면 꼭 찾아와야 해?","JPN":"じゃあ、シグマはここで待ってるから、時間ができたら呼びにきてね。絶対だよ？","ENG":"Sigma's gonna wait here, so don't forget to visit when you have time, okay?","TWN":"那西格瑪就在這裡等爸爸，爸爸忙完後一定要來找我喔？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":" "},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_CA_SIGMA_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};